import{c as a,Q as e,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"MultiAgentBench: Evaluating the Collaboration and Competition of LLM Agents","description":"","frontmatter":{"title":"MultiAgentBench: Evaluating the Collaboration and Competition of LLM Agents","arxiv_id":2503.01935,"authors":"Kunlun Zhu, Hongyi Du, Zhaochen Hong, et al.","published":"2025-03-03T00:00:00.000Z","source":"https://arxiv.org/abs/2503.01935","source_tier":"P"},"headers":[],"relativePath":"research/papers/2025-03-03-multiagentbench-collaboration-competition-2503-01935.md","filePath":"research/papers/2025-03-03-multiagentbench-collaboration-competition-2503-01935.md","lastUpdated":1779901665000}'),r={name:"research/papers/2025-03-03-multiagentbench-collaboration-competition-2503-01935.md"};function i(d,t,h,l,s,c){return e(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="multiagentbench-evaluating-the-collaboration-and-competition-of-llm-agents" tabindex="-1">MultiAgentBench: Evaluating the Collaboration and Competition of LLM Agents <a class="header-anchor" href="#multiagentbench-evaluating-the-collaboration-and-competition-of-llm-agents" aria-label="Permalink to &quot;MultiAgentBench: Evaluating the Collaboration and Competition of LLM Agents&quot;">​</a></h1><p><strong>ArXiv</strong>: 2503.01935 | <strong>Date</strong>: 2025-03-03 | <strong>Authors</strong>: Kunlun Zhu, Hongyi Du, Zhaochen Hong, et al. | <strong>Category</strong>: cs.MA, cs.AI, cs.CL</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>全面評估框架，評估 LLM 多 agent 系統在多樣化互動場景中的協作與競爭能力。核心問題：「現有基準要麼只關注單 agent 任務，要麼僅限於特定領域」。引入里程碑式 KPI（Milestone-based Key Performance Indicators）捕捉超越傳統成功指標的細微協作面向。</p><h2 id="評估方法" tabindex="-1">評估方法 <a class="header-anchor" href="#評估方法" aria-label="Permalink to &quot;評估方法&quot;">​</a></h2><h3 id="協調拓撲測試" tabindex="-1">協調拓撲測試 <a class="header-anchor" href="#協調拓撲測試" aria-label="Permalink to &quot;協調拓撲測試&quot;">​</a></h3><table tabindex="0"><thead><tr><th>拓撲結構</th><th>描述</th></tr></thead><tbody><tr><td>星形（Star）</td><td>中央協調者 + 周圍 agents</td></tr><tr><td>鏈形（Chain）</td><td>序列傳遞</td></tr><tr><td>樹形（Tree）</td><td>階層式協調</td></tr><tr><td>圖形（Graph）</td><td>任意連接</td></tr></tbody></table><p>此外測試：群體討論（Group discussion）、認知計畫（Cognitive planning）</p><h2 id="主要發現" tabindex="-1">主要發現 <a class="header-anchor" href="#主要發現" aria-label="Permalink to &quot;主要發現&quot;">​</a></h2><table tabindex="0"><thead><tr><th>發現</th><th>量化結果</th></tr></thead><tbody><tr><td>最高任務分數模型</td><td><strong>GPT-4o-mini</strong>（非最強模型）</td></tr><tr><td>最有效拓撲（研究場景）</td><td><strong>圖形結構</strong>（Graph topology）</td></tr><tr><td>認知計畫提升</td><td>里程碑達成率 <strong>+3%</strong></td></tr></tbody></table><p><strong>關鍵洞見</strong>：小型模型在適當協調下可勝過更大模型，協調架構本身是關鍵。</p><h2 id="與-mafbench-的關係" tabindex="-1">與 MAFBench 的關係 <a class="header-anchor" href="#與-mafbench-的關係" aria-label="Permalink to &quot;與 MAFBench 的關係&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>MultiAgentBench</th><th>MAFBench (2602.03128)</th></tr></thead><tbody><tr><td>焦點</td><td>協作與競爭場景</td><td>框架架構影響</td></tr><tr><td>指標</td><td>里程碑式 KPI</td><td>延遲/準確率/協調成功率</td></tr><tr><td>發現方向</td><td>任務多樣性</td><td>架構選擇影響（100×）</td></tr></tbody></table><p>兩者互補：MultiAgentBench 提供任務覆蓋，MAFBench 提供框架架構洞察。</p><h2 id="代碼與資料集" tabindex="-1">代碼與資料集 <a class="header-anchor" href="#代碼與資料集" aria-label="Permalink to &quot;代碼與資料集&quot;">​</a></h2><p>公開可用，支持可重現性。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Benchmark &amp; Evaluation / Agent Architecture &amp; Coordination</strong> — 2025 年多 agent 評估的基礎基準，里程碑式 KPI 設計值得在評估 workspace 中的 sub-agent 性能時借鑑。</p>',18)])])}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
